---
/**
 * @component Alert
 * @title Alert
 * @description A prominent message that draws user attention to important information.
 * @figmaUrl https://www.figma.com/design/koxai7zw5vIuBzuVxe5T2l/BejamasUI---Design-System?node-id=2536-3189&t=YFStJ3V8fXEO8QD8-4
 *
 * @preview
 *
 * <div class="grid w-full max-w-xl items-start gap-4">
 *   <Alert>
 *     <CircleCheckIcon size={32} />
 *     <AlertTitle>Success! Your changes have been saved</AlertTitle>
 *     <AlertDescription>This is an alert with title and description.</AlertDescription>
 *   </Alert>
 *
 *   <Alert>
 *     <AlertTitle>This Alert has a title and an icon. No description.</AlertTitle>
 *   </Alert>
 *
 *   <Alert variant="destructive">
 *     <AlertTitle>Unable to process your payment.</AlertTitle>
 *     <AlertDescription>
 *       <p>Please verify your billing information and try again.</p>
 *       <ul class="list-inside list-disc text-sm">
 *         <li>Check your card details</li>
 *         <li>Ensure sufficient funds</li>
 *         <li>Verify billing address</li>
 *       </ul>
 *     </AlertDescription>
 *   </Alert>
 * </div>
 *
 * @usage
 *
 * ```astro nocollapse
 * ---
 * import { Alert, AlertTitle, AlertDescription } from '@bejamas/ui/components/alert';
 * ---
 * <Alert variant="default">
 *   <CircleCheckIcon size={32} />
 *   <AlertTitle>Heads up!</AlertTitle>
 *   <AlertDescription>Something happened successfully.</AlertDescription>
 * </Alert>
 * ```
 */
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

type AlertVariant = "default" | "destructive";

interface Props extends HTMLAttributes<"div"> {
  variant?: AlertVariant;
  class?: string;
}

const {
  class: className = "",
  variant = "default",
  ...rest
} = Astro.props as Props;

const alertVariants = cva(
  "grid gap-0.5 rounded-lg border px-4 py-3 text-left text-sm has-data-[slot=alert-action]:relative has-data-[slot=alert-action]:pr-18 has-[>svg]:grid-cols-[auto_1fr] has-[>svg]:gap-x-2.5 *:[svg]:row-span-2 *:[svg]:translate-y-0.5 *:[svg]:text-current *:[svg:not([class*='size-'])]:size-4 gap-y-0.5 rounded-xl border-border bg-card has-[>svg]:grid-cols-[calc(var(--spacing)*4)_1fr] has-[>svg]:gap-x-3 items-start [&>svg]:size-4 [&>svg]:translate-y-0.5 [&>svg]:text-current group/alert relative w-full",
  {
    variants: {
      variant: {
        default: "bg-card text-card-foreground",
        destructive: "text-destructive bg-card *:data-[slot=alert-description]:text-destructive/90 *:[svg]:text-current",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);
---

<div
  {...rest}
  data-slot="alert"
  role="alert"
  class={cn(alertVariants({ variant }), className)}
>
  <slot />
</div>

